  border-bottom: 1px solid #e2e8f0;
  padding-bottom: 0.8rem;
}

.evidence-list li:last-child {
  border-bottom: 0;
  padding-bottom: 0;
}

.evidence-list p {
  color: #607284;
}

.evidence-list pre,
.raw-json pre {
  margin-top: 0.5rem;
  border-radius: 10px;
  background: #0f172a;
  color: #e2e8f0;
  padding: 0.65rem;
  overflow-x: auto;
  font-size: 0.8rem;
}

.markdown-card {
  line-height: 1.7;
}

.markdown-card h1,
.markdown-card h2,
.markdown-card h3 {
  margin: 0.9rem 0 0.5rem;
}

.markdown-card p,
.markdown-card ul,
.markdown-card ol {
  margin: 0.5rem 0;
}

.raw-json summary {
  font-weight: 600;
  cursor: pointer;
}

.toast {
  position: fixed;
  top: 1rem;
  right: 1rem;
  background: #1f2937;
  color: #f9fafb;
  padding: 0.5rem 0.85rem;
  border-radius: 8px;
  box-shadow: 0 8px 18px rgba(15, 23, 42, 0.35);
  z-index: 50;
}

@media (max-width: 720px) {
  .summary-header {
    flex-direction: column;
    align-items: flex-start;
  }

  .page {
    padding: 1rem 0.75rem 2rem;
  }

  .button-row {
    width: 100%;
  }

  .secondary-button {
    flex: 1 1 220px;
  }
}

export type ReviewStatus = 'queued' | 'running' | 'succeeded' | 'failed' | 'cancelled';

export type ReviewSeverity = 'critical' | 'high' | 'medium' | 'low';
export type ReviewConfidence = 'high' | 'medium' | 'low';
export type ReviewRecommendation = 'approve' | 'comment' | 'request_changes';

export interface ReviewFindingLocation {
  path: string;
  line: number;
}

export interface ReviewSuggestedFix {
  kind: 'text';
  value: string;
}

export interface ReviewFinding {
  id: string;
  severity: ReviewSeverity;
  confidence: ReviewConfidence;
  title: string;
  description: string;
  conditions: string | null;
  locations: ReviewFindingLocation[];
  suggestedFix: ReviewSuggestedFix | null;
  evidenceRefs: string[];
}

export interface ReviewEvidence {
  id: string;
  type: string;
  label: string;
  status: 'passed' | 'failed' | 'warning' | 'info';
  metadata?: Record<string, unknown>;
}

export interface ReviewSummary {
  riskLevel: ReviewSeverity;
  findingCounts: Record<ReviewSeverity, number>;
  recommendation: ReviewRecommendation;
}

export interface ReviewResponse {
  id: string;
  status: ReviewStatus;
  createdAt: string;
  updatedAt: string;
  startedAt: string | null;
  finishedAt: string | null;
  summary?: ReviewSummary;
  findings: ReviewFinding[];
  evidence: ReviewEvidence[];
  markdownSummary: string | null;
  error?: {
    code: string;
    message: string;
  };
}

export interface GetReviewResponse {
  review: ReviewResponse;
}

